sp_angular_provider.script:
function scmTableSavedFiltersService() {
    "use strict";

    function getSavedFilters(options) {
        options = options || {};

        return options.server
            .get({
                action: "getSavedFilters",
                transactionId: options.transactionId,
                tableProviderScriptInclude: options.tableProviderScriptInclude,
            })
            .then(function (response) {
                return response.data.savedFilters || [];
            });
    }

    function saveFilter(options) {
        options = options || {};

        return options.server
            .get({
                action: "saveFilter",
                transactionId: options.transactionId,
                tableProviderScriptInclude: options.tableProviderScriptInclude,
                filterName: options.filterName,
                filters: options.filters,
            })
            .then(function (response) {
                return response.data.savedFilters || [];
            });
    }

    function deleteFilter(options) {
        options = options || {};

        return options.server
            .get({
                action: "deleteFilter",
                transactionId: options.transactionId,
                tableProviderScriptInclude: options.tableProviderScriptInclude,
                filterId: options.filterId,
            })
            .then(function (response) {
                return response.data.savedFilters || [];
            });
    }

    function setDefaultFilter(options) {
        options = options || {};

        return options.server
            .get({
                action: "setDefaultFilter",
                transactionId: options.transactionId,
                tableProviderScriptInclude: options.tableProviderScriptInclude,
                filterId: options.filterId,
            })
            .then(function (response) {
                return response.data.savedFilters || [];
            });
    }

    return {
        getSavedFilters: getSavedFilters,
        saveFilter: saveFilter,
        deleteFilter: deleteFilter,
        setDefaultFilter: setDefaultFilter,
    };
}
